import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    /**
     * Adiciona transações em lote com tratamento de erro granulado.
     */
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const sanitizedPayload = transactions
                .map(t => {
                    const amount = Number(t.amount);
                    if (isNaN(amount)) return null;
                    if (!t.transaction_date || !t.description || !t.user_id) return null;
                    if (!t.row_hash) return null;

                    return {
                        transaction_date: t.transaction_date,
                        amount: amount,
                        description: String(t.description).trim().substring(0, 500),
                        type: t.type || (amount >= 0 ? 'income' : 'expense'),
                        pix_key: t.pix_key || null,
                        source: t.source || 'file',
                        user_id: t.user_id,
                        bank_id: t.bank_id || null, 
                        status: t.status || 'pending',
                        row_hash: t.row_hash
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            if (sanitizedPayload.length === 0) return [];

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .insert(sanitizedPayload)
                .select();

            if (error) {
                console.error("[Consolidation:INSERT_ERROR]", error);
                throw new Error(`Falha na gravação: ${error.message}`);
            }
            return data || [];
        } catch (e: any) {
            console.error("[Consolidation:CRITICAL_FAIL]", e);
            throw e;
        }
    },

    /**
     * Busca registros existentes para evitar duplicidade.
     * CRÍTICO: Se esta função falhar, o chamador deve interromper o processo para evitar 'lista vazia falsa'.
     */
    getExistingTransactionsForDedup: async (userId: string, bankId?: string) => {
        try {
            if (!userId) throw new Error("UserID é obrigatório para deduplicação.");

            let query = supabase
                .from('consolidated_transactions')
                .select('row_hash') // Buscamos apenas o hash para economia de banda
                .eq('user_id', userId)
                .eq('status', 'pending');

            // Filtro rigoroso por bank_id
            if (bankId) {
                if (bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank') {
                    query = query.is('bank_id', null);
                } else {
                    // Garante que é um UUID antes de filtrar no SQL
                    const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-5][0-9a-f]{3}-[089ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(bankId);
                    if (isUuid) {
                        query = query.eq('bank_id', bankId);
                    } else {
                        // Se não for UUID e nem virtual, tratamos como isolado sem bank_id
                        query = query.is('bank_id', null);
                    }
                }
            }

            const { data, error } = await query;

            if (error) {
                console.error("[Consolidation:FETCH_DEDUP_ERROR]", error);
                throw new Error("Falha ao validar duplicidade. O processo foi interrompido por segurança.");
            }

            return data || [];
        } catch (e) {
            throw e;
        }
    },

    /**
     * Limpeza segura e isolada por bank_id.
     */
    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!userId) return false;

            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId && bankId !== 'all') {
                if (bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank') {
                    query = query.is('bank_id', null);
                } else {
                    query = query.eq('bank_id', bankId);
                }
            }

            const { error } = await query;
            if (error) throw error;

            return true;
        } catch (error) {
            console.error("[Consolidation:DELETE_FAIL]", error);
            throw error;
        }
    },

    /**
     * Recupera todas as transações pendentes do usuário para hidratação da UI.
     */
    getPendingTransactions: async (userId: string) => {
        try {
            if (!userId) return [];
            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('id, transaction_date, amount, description, type, bank_id, row_hash')
                .eq('user_id', userId)
                .eq('status', 'pending')
                .order('transaction_date', { ascending: false });

            if (error) throw error;
            return data || [];
        } catch (e) {
            console.error("[Consolidation:FETCH_PENDING_FAIL]", e);
            throw e; 
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);
            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao deletar transação única:", error);
            throw error;
        }
    }
};

import { consolidationService } from './ConsolidationService';
import { Transaction } from '../types';
import { Logger } from './monitoringService';

export const LaunchService = {
    /**
     * Gera Row Hash baseado no conteúdo integral da linha + Usuário + Banco.
     * V13: Inclui sinal e bank_id para garantir unicidade absoluta.
     */
    computeRowHash: (t: any, userId: string) => {
        const normalize = (v: any) => String(v || '')
            .trim()
            .toLowerCase()
            .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
            .replace(/[^a-z0-9]/g, '');

        const date = normalize(t.date || t.transaction_date);
        const desc = normalize(t.description);
        // Garantimos que bankId seja parte da entropia do hash
        const bankId = normalize(t.bank_id || 'virtual-source');
        const user = normalize(userId);

        const rawAmount = Number(t.amount || 0);
        const amountVal = Math.abs(rawAmount * 100).toFixed(0);
        const sign = rawAmount < 0 ? 'D' : 'C'; 

        const raw = `${date}|${desc}|${amountVal}${sign}|${user}|${bankId}`;

        let hash = 0;
        for (let i = 0; i < raw.length; i++) {
            const char = raw.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; 
        }
        return `h${Math.abs(hash).toString(36)}`;
    },

    /**
     * Orquestra o lançamento seguro de transações.
     * BLOQUEIO DE SEGURANÇA: Se não conseguir ler os existentes, não grava nada para evitar lixo.
     */
    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || !transactions || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions ? transactions.length : 0 };
        }

        const totalReceived = transactions.length;
        const currentBankId = (bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank') ? null : bankId;

        try {
            // 1. FASE DE VALIDAÇÃO (Deduplicação)
            // Se esta chamada falhar, ela joga um erro capturado no catch abaixo, abortando a persistência.
            const existingData = await consolidationService.getExistingTransactionsForDedup(userId, bankId);

            const existingHashes = new Set(existingData.map(t => t.row_hash).filter(Boolean));

            // 2. FILTRAGEM
            const toPersist = transactions
                .map(item => {
                    const rowHash = this.computeRowHash({ ...item, bank_id: currentBankId }, userId);
                    if (existingHashes.has(rowHash)) return null;

                    return {
                        transaction_date: item.date,
                        amount: item.amount,
                        description: item.description,
                        type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        source: source,
                        user_id: userId,
                        bank_id: currentBankId,
                        row_hash: rowHash,
                        status: 'pending' as const
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            const novosCount = toPersist.length;
            const ignoradosCount = totalReceived - novosCount;

            if (novosCount === 0) {
                return { added: 0, skipped: totalReceived, total: totalReceived };
            }

            // 3. PERSISTÊNCIA ATÔMICA
            await consolidationService.addTransactions(toPersist as any);

            Logger.info(`[Launch:OK] Banco ${bankId || 'Virtual'} | Novos: ${novosCount}`);
            return { added: novosCount, skipped: ignoradosCount, total: totalReceived };

        } catch (e: any) {
            Logger.error(`[Launch:ABORT] Banco ${bankId || 'Virtual'} interrompido por erro de sincronia.`, e);
            throw e; // Propaga para que a UI bloqueie apenas este banco
        }
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<boolean> {
        try {
            return await consolidationService.deletePendingTransactions(userId, bankId);
        } catch (error) {
            console.error("[LaunchService] Falha ao limpar lançamentos do banco:", error);
            throw error;
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: any) => {
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    /**
     * Recupera os dados da Lista Viva do servidor.
     * Mantém o estado local em caso de erro transitório de rede.
     */
    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                const bankId = t.bank_id || 'gmail-sync';
                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    cleanedDescription: t.description
                };
                if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                groupedByBank[bankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId === 'gmail-sync' ? 'Sincronização Gmail' : `Lista Viva (Sincronizada)`,
                processedTransactions: txs,
                isRestored: true
            }));

            setBankStatementFile(() => restoredFiles);
            setSelectedBankIds((prev: string[]) => {
                const ids = restoredFiles.map(f => f.bankId);
                // Preserva seleção ativa se os bancos ainda existem na lista restaurada
                return Array.from(new Set([...prev.filter(id => ids.includes(id)), ...ids]));
            });

        } catch (err: any) {
            console.error("[Lista Viva] Erro crítico de hidratação:", err);
            setSyncError(err.message);
            // NÃO limpamos setBankStatementFile aqui para evitar que a UI mostre 'vazio' por erro de rede
        } finally {
            isHydrating.current = false;
        }
    }, [user, setBankStatementFile, setSelectedBankIds, isCleaning]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
            await hydrate();
            return stats;
        } catch (e: any) {
            // O erro já foi logado no LaunchService
            throw e; 
        }
    }, [user, hydrate]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            await consolidationService.deletePendingTransactions(user.id, bankId);
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

