import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';
import { useUI } from '../contexts/UIContext';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds
}: any) => {
    const { showToast } = useUI();
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    /**
     * Recupera os dados da Lista Viva do servidor.
     * Mantém o estado local em caso de erro transitório de rede.
     */
    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                const bankId = t.bank_id || 'gmail-sync';
                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    cleanedDescription: t.description
                };
                if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                groupedByBank[bankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId === 'gmail-sync' ? 'Sincronização Gmail' : `Lista Viva (Sincronizada)`,
                processedTransactions: txs,
                isRestored: true
            }));

            setBankStatementFile(() => restoredFiles);
            setSelectedBankIds((prev: string[]) => {
                const ids = restoredFiles.map(f => f.bankId);
                // Preserva seleção ativa se os bancos ainda existem na lista restaurada
                return Array.from(new Set([...prev.filter(id => ids.includes(id)), ...ids]));
            });

        } catch (err: any) {
            console.error("[Lista Viva] Erro crítico de hidratação:", err);
            const msg = err.message || "Erro desconhecido na sincronização.";
            setSyncError(msg);

            // Se for erro de esquema, avisa o usuário com toast persistente
            if (msg.includes('ERRO_COLUNA_AUSENTE')) {
                showToast("Banco de dados desatualizado. Acesse o Admin e execute o Diagnóstico.", "error");
            } else {
                showToast("Falha ao recuperar Lista Viva: " + msg, "error");
            }
        } finally {
            isHydrating.current = false;
        }
    }, [user, setBankStatementFile, setSelectedBankIds, isCleaning, showToast]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
            await hydrate();
            return stats;
        } catch (e: any) {
            // O erro já foi logado no LaunchService
            showToast("Erro no Lançamento: " + (e.message || "Erro de rede."), "error");
            throw e; 
        }
    }, [user, hydrate, showToast]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            await consolidationService.deletePendingTransactions(user.id, bankId);
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    /**
     * Adiciona transações em lote com tratamento de erro granulado.
     */
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const sanitizedPayload = transactions
                .map(t => {
                    const amount = Number(t.amount);
                    if (isNaN(amount)) return null;
                    if (!t.transaction_date || !t.description || !t.user_id) return null;
                    if (!t.row_hash) return null;

                    // Validação rigorosa de formato de data YYYY-MM-DD
                    // Isso evita enviar lixo como "Associado:" para uma coluna DATE do Postgres
                    const isIsoDate = /^\d{4}-\d{2}-\d{2}$/.test(t.transaction_date);
                    if (!isIsoDate) {
                        console.warn("[Consolidation:SKIP] Data inválida detectada:", t.transaction_date);
                        return null;
                    }

                    return {
                        transaction_date: t.transaction_date,
                        amount: amount,
                        description: String(t.description).trim().substring(0, 500),
                        type: t.type || (amount >= 0 ? 'income' : 'expense'),
                        pix_key: t.pix_key || null,
                        source: t.source || 'file',
                        user_id: t.user_id,
                        bank_id: t.bank_id || null, 
                        status: t.status || 'pending',
                        row_hash: t.row_hash
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            if (sanitizedPayload.length === 0) {
                console.warn("[Consolidation:EMPTY] Nenhuma transação válida após sanitização.");
                return [];
            }

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .insert(sanitizedPayload)
                .select();

            if (error) {
                console.error("[Consolidation:INSERT_ERROR]", error);
                throw new Error(error.message || "Erro desconhecido ao salvar transações.");
            }
            return data || [];
        } catch (e: any) {
            console.error("[Consolidation:CRITICAL_FAIL]", e);
            throw e;
        }
    },

    /**
     * Busca registros existentes para evitar duplicidade.
     */
    getExistingTransactionsForDedup: async (userId: string, bankId?: string) => {
        try {
            if (!userId) throw new Error("UserID é obrigatório.");

            let query = supabase
                .from('consolidated_transactions')
                .select('row_hash')
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId) {
                const isVirtual = bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank';
                const isProbablyUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);

                if (isVirtual || !isProbablyUuid) {
                    query = query.is('bank_id', null);
                } else {
                    query = query.eq('bank_id', bankId);
                }
            }

            const { data, error } = await query;

            if (error) {
                console.error("[Consolidation:FETCH_DEDUP_ERROR]", error);
                if (error.code === '42703' || (error.message && error.message.includes('column'))) {
                    throw new Error("ERRO_COLUNA_AUSENTE: O banco de dados precisa de atualização (Script V8).");
                }
                throw new Error(error.message || "Falha ao validar duplicidade.");
            }

            return data || [];
        } catch (e: any) {
            throw e;
        }
    },

    /**
     * Limpeza segura e isolada por bank_id.
     */
    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!userId) return false;

            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId && bankId !== 'all') {
                const isVirtual = bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank';
                const isProbablyUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);

                if (isVirtual || !isProbablyUuid) {
                    query = query.is('bank_id', null);
                } else {
                    query = query.eq('bank_id', bankId);
                }
            }

            const { error } = await query;
            if (error) throw error;

            return true;
        } catch (error) {
            console.error("[Consolidation:DELETE_FAIL]", error);
            throw error;
        }
    },

    /**
     * Recupera todas as transações pendentes do usuário.
     */
    getPendingTransactions: async (userId: string) => {
        try {
            if (!userId) return [];

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('id, transaction_date, amount, description, type, bank_id, row_hash')
                .eq('user_id', userId)
                .eq('status', 'pending')
                .order('transaction_date', { ascending: false });

            if (error) {
                console.error("[Consolidation:FETCH_PENDING_FAIL]", error);
                if (error.code === 'PGRST100' || error.code === '42703' || (error.message && error.message.includes('column'))) {
                    throw new Error("ERRO_COLUNA_AUSENTE: O banco de dados precisa de atualização (Script V8).");
                }
                throw error;
            }
            return data || [];
        } catch (e: any) {
            throw e; 
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);
            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao deletar transação única:", error);
            throw error;
        }
    }
};

import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { extractTransactionsFromComplexBlock } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V11 - AUTO-FILTRAGEM DE RUÍDO)
 */
export const ContractExecutor = {
    async apply(model: FileModel, normalizedContent: string): Promise<Transaction[]> {
        if (!model || !model.mapping) {
            console.error("[Executor:ABORT] Falha de integridade: Mapeamento ausente.");
            return [];
        }

        const sourceContent = normalizedContent || model.snippet || "";
        const lines = sourceContent.split(/\r?\n/).filter(l => l.trim().length > 0);

        console.log(`[Executor:INPUT] Aplicando Modelo: "${model.name}" | Linhas: ${lines.length}`);

        if (lines.length === 0) return [];

        const extractionMode = model.mapping.extractionMode || 'COLUMNS';
        let results: Transaction[] = [];

        try {
            if (extractionMode === 'BLOCK') {
                const aiResults = await extractTransactionsFromComplexBlock(sourceContent);
                results = (aiResults || []).map((tx: any, idx: number) => ({
                    id: `block-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date,
                    description: tx.description,
                    rawDescription: tx.description,
                    amount: Number(tx.amount) || 0,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description,
                    contributionType: tx.type || 'AUTO',
                    paymentMethod: tx.paymentMethod || 'OUTROS'
                }));
            } 
            else {
                const { 
                    dateColumnIndex, 
                    descriptionColumnIndex, 
                    amountColumnIndex, 
                    paymentMethodColumnIndex, 
                    typeColumnIndex,
                    skipRowsStart 
                } = model.mapping;

                const delimiter = model.fingerprint.delimiter || ';';
                const yearAnchor = DateResolver.discoverAnchorYear(sourceContent);

                results = lines.reduce((acc: Transaction[], line, index) => {
                    if (index < (skipRowsStart || 0)) return acc;

                    const cols = line.split(delimiter);

                    const rawDate = (dateColumnIndex !== -1 && cols[dateColumnIndex] !== undefined) ? (cols[dateColumnIndex] || '').trim() : '';
                    const rawDesc = (descriptionColumnIndex !== -1 && cols[descriptionColumnIndex] !== undefined) ? (cols[descriptionColumnIndex] || '').trim() : '';
                    const rawAmount = (amountColumnIndex !== -1 && cols[amountColumnIndex] !== undefined) ? (cols[amountColumnIndex] || '').trim() : '';

                    if (!rawDate && !rawDesc && !rawAmount) return acc;

                    // RESOLUÇÃO DE DATA
                    const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);

                    // FILTRO CRÍTICO: Se a data não pôde ser resolvida como YYYY-MM-DD, a linha é RUÍDO (Cabeçalho/Rodapé)
                    if (!isoDate || !/^\d{4}-\d{2}-\d{2}$/.test(isoDate)) {
                        return acc;
                    }

                    const stdAmount = AmountResolver.clean(rawAmount);
                    const numericValue = parseFloat(stdAmount);

                    acc.push({
                        id: `col-${model.id}-${index}-${Date.now()}`,
                        date: isoDate,
                        description: rawDesc,
                        rawDescription: rawDesc,
                        amount: isNaN(numericValue) ? 0 : numericValue,
                        originalAmount: rawAmount,
                        cleanedDescription: rawDesc, 
                        contributionType: (typeColumnIndex !== undefined && typeColumnIndex !== -1 && cols[typeColumnIndex]) 
                            ? cols[typeColumnIndex].trim().toUpperCase() 
                            : 'AUTO',
                        paymentMethod: (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex !== -1 && cols[paymentMethodColumnIndex]) 
                            ? cols[paymentMethodColumnIndex].trim().toUpperCase() 
                            : 'OUTROS'
                    });

                    return acc;
                }, []);
            }

            console.log(`[Executor:SUCCESS] ${results.length} transações legítimas extraídas.`);
            return results;

        } catch (error) {
            console.error(`[Executor:ERROR] Falha no modelo ${model.name}:`, error);
            return [];
        }
    }
};

