export const LaunchService = {
    /**
     * Gera Row Hash baseado no conteúdo integral da linha.
     * V14: FIDELIDADE TOTAL. Não remove espaços nem caracteres especiais no hash
     * para garantir que 'PEDRO PIX' e 'PEDRO' sejam tratados como diferentes.
     */
    computeRowHash: (t: any, userId: string) => {
        const date = String(t.date || t.transaction_date || '').trim();
        const desc = String(t.description || '').trim().toUpperCase();
        const bankId = String(t.bank_id || 'virtual').trim();
        const user = String(userId).trim();

        const rawAmount = Number(t.amount || 0);
        const amountVal = Math.abs(rawAmount * 100).toFixed(0);
        const sign = rawAmount < 0 ? 'D' : 'C'; 

        // String de entropia sem normalização destrutiva
        const raw = `${date}|${desc}|${amountVal}${sign}|${user}|${bankId}`;

        let hash = 0;
        for (let i = 0; i < raw.length; i++) {
            const char = raw.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; 
        }
        return `h${Math.abs(hash).toString(36)}`;
    },

    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || !transactions || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions ? transactions.length : 0 };
        }

        const totalReceived = transactions.length;
        const currentBankId = (bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank') ? null : bankId;

        try {
            // 1. Busca hashes existentes para evitar duplicados reais
            const existingData = await consolidationService.getExistingTransactionsForDedup(userId, bankId);
            const existingHashes = new Set(existingData.map(t => t.row_hash).filter(Boolean));

            // 2. Mapeia para o formato do banco SEM LIMPAR a descrição
            const toPersist = transactions
                .map(item => {
                    // Importante: item.description aqui é o que a IA entregou no modelo
                    const rowHash = this.computeRowHash({ ...item, bank_id: currentBankId }, userId);
                    if (existingHashes.has(rowHash)) return null;

                    return {
                        transaction_date: item.date,
                        amount: item.amount,
                        description: item.description, // FIDELIDADE: Usa a descrição bruta extraída
                        type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        source: source,
                        user_id: userId,
                        bank_id: currentBankId,
                        row_hash: rowHash,
                        status: 'pending' as const
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            const novosCount = toPersist.length;

            if (novosCount === 0) {
                return { added: 0, skipped: totalReceived, total: totalReceived };
            }

            // 3. Salva no banco
            await consolidationService.addTransactions(toPersist as any);

            return { added: novosCount, skipped: totalReceived - novosCount, total: totalReceived };

        } catch (e: any) {
            Logger.error(`[Launch:ERROR] Falha no banco ${bankId}`, e);
            throw e;
        }
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<boolean> {
        try {
            return await consolidationService.deletePendingTransactions(userId, bankId);
        } catch (error) {
            throw error;
        }
    }
};

/**
 * 🎯 FONTE ÚNICA DE VERDADE: INTELIGÊNCIA NOMINAL
 * Centraliza toda a lógica de sanitização de nomes e descrições.
 */
export class NameResolver {

  private static CONTROL_KEYWORDS = [
    'SALDO', 'TOTAL', 'SOMATORIO', 'RESUMO', 'FECHAMENTO', 
    'ACUMULADO', 'DISPONIVEL', 'APLICACAO', 'RESGATE', 'SALDO ANTERIOR', 'SUBTOTAL',
    'RENDIMENTO', 'TARIFAS', 'IOF', 'JUROS', 'IRRF', 'SDO'
  ];

  static identifyNameColumn(rows: string[][], excludedIndices: number[] = []): number {
    const sample = rows.slice(0, 50);
    if (sample.length === 0) return -1;
    const scores = new Array(rows[0]?.length || 0).fill(0);
    sample.forEach(row => {
        row.forEach((cell, index) => {
            if (excludedIndices.includes(index)) return;
            const val = String(cell || '').trim();
            if (val.length > 4 && !/^[\d.,R$\s\-()]+$/.test(val)) {
                scores[index] += 1;
                if (val.split(' ').length > 1) scores[index] += 0.5;
            }
        });
    });
    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : -1;
  }

  /**
   * LIMPEZA: No modo modelo, userKeywords virá vazio, 
   * resultando em retorno direto do texto original.
   */
  static clean(rawName: string, userKeywords: string[] = []): string {
    if (!rawName) return '';
    if (userKeywords.length === 0) return rawName.trim();

    let cleaned = rawName;
    const sortedKeywords = [...userKeywords].sort((a, b) => b.length - a.length);
    sortedKeywords.forEach(k => {
      if (k && k.trim()) {
          const escaped = k.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          cleaned = cleaned.replace(new RegExp(`\\b${escaped}\\b`, 'gi'), ' ');
      }
    });

    return cleaned.replace(/\s+/g, ' ').trim() || rawName.trim();
  }

  static cleanGenericNoise(text: string): string {
    const noise = /\b(PIX|TED|DOC|TRANSF|TRANSFERENCIA|RECEBIDO|ENVIADO|PAGTO|PAGAMENTO|AUTENTICACAO)\b/gi;
    return text.replace(noise, ' ').replace(/\s+/g, ' ').trim();
  }

  /**
   * NORMALIZAÇÃO: Usada apenas para MATCHING (comparar nomes).
   * Não deve ser usada para salvar ou exibir o dado.
   */
  static normalize(text: string): string {
    if (!text) return '';
    return text
      .toUpperCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '') 
      .replace(/\s+/g, ' ')           
      .trim();
  }

  static isControlRow(text: string): boolean {
    if (!text) return false;
    const norm = this.normalize(text);
    return this.CONTROL_KEYWORDS.some(k => norm.includes(k));
  }
}

