/**
 * 📜 CONTRACT EXECUTOR (V13 - SINCRONIA LAB-PROD)
 * Este motor agora usa o "Gabarito" (snippet) para garantir que a IA
 * processe o arquivo novo exatamente como processou no Laboratório.
 */
export const ContractExecutor = {
    async apply(model: FileModel, normalizedContent: string): Promise<Transaction[]> {
        if (!model || !model.mapping) {
            console.error("[Executor:ABORT] Falha de integridade: Mapeamento ausente.");
            return [];
        }

        const sourceContent = normalizedContent || "";
        const lines = sourceContent.split(/\r?\n/).filter(l => l.trim().length > 0);

        console.log(`[Executor:PROCESS] Aplicando Inteligência do Modelo: "${model.name}"`);

        if (lines.length === 0) return [];

        // NOVIDADE: Enviamos o arquivo NOVO + o SNIPPET (Aprendizado) para a IA
        const extractionMode = model.mapping.extractionMode || 'COLUMNS';
        let results: Transaction[] = [];

        try {
            // No modo Aprendido, confiamos na IA para extrair conforme o gabarito que salvamos (model.snippet)
            const aiResults = await extractTransactionsWithModel(sourceContent, model.snippet || undefined);

            results = (aiResults || []).map((tx: any, idx: number) => {
                const stdAmount = AmountResolver.clean(tx.amount);
                const numericValue = parseFloat(stdAmount);

                return {
                    id: `exec-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date || new Date().toISOString().split('T')[0],
                    description: tx.description || 'Sem descrição',
                    rawDescription: tx.description,
                    amount: isNaN(numericValue) ? 0 : numericValue,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description, // IA já entregou limpo conforme gabarito
                    contributionType: tx.type || 'AUTO',
                    paymentMethod: tx.paymentMethod || 'OUTROS'
                };
            });

            console.log(`[Executor:SUCCESS] ${results.length} transações extraídas via Inteligência Aplicada.`);
            return results;

        } catch (error) {
            console.error(`[Executor:ERROR] Falha no motor de inteligência aplicada:`, error);
            return [];
        }
    }
};

import { Transaction, FileModel } from '../types';
import { StrategyEngine } from '../core/strategies';
import { Fingerprinter } from '../core/processors/Fingerprinter';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

export * from './utils/parsingUtils';
