 */
const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    if (typeof input === 'object' && !Array.isArray(input)) {
        return input.rows || input.transactions || input;
    }

    let sanitized = String(input).trim();
    // Remove markdown code blocks
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || parsed;
    } catch (e) {
        console.warn("[IA:REPAIR] Tentando reparar JSON truncado...");
        let repaired = sanitized;
        // Tenta fechar colchetes ou chaves se a IA parou no meio (comum em arquivos grandes)
        if (!repaired.endsWith(']}')) {
            if (repaired.includes('"rows": [')) {
                repaired = repaired.substring(0, repaired.lastIndexOf('}') + 1);
                if (!repaired.endsWith(']')) repaired += ']';
                if (!repaired.endsWith('}')) repaired += '}';
            }
        }
        try {
            const secondAttempt = JSON.parse(repaired);
            return secondAttempt.rows || secondAttempt;
        } catch (inner) {
            console.error("[IA:PARSE_FAIL] Não foi possível recuperar os dados.");
            return fallback;
        }
    }
};

